"use client";

import { Fragment, useEffect, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { markStepDone } from "@/lib/progress";

const topicId = "data";

// ===== 第一层：回顾内容（前 6 步关键操作） =====
const REVIEW_ITEMS = [
  { icon: "✋", step: "1", label: "摸一摸", text: "你调查了同学最喜欢的水果" },
  { icon: "⚖️", step: "2", label: "比一比", text: "你比较了男生和女生不同的喜好" },
  { icon: "🔢", step: "3", label: "数一数", text: "你用正字法记录了水果数量" },
  { icon: "✏️", step: "4", label: "画一画", text: "你把数据画成了条形图" },
  { icon: "🔄", step: "5", label: "变一变", text: "你发现分类方式不同，总数不变" },
  { icon: "🏠", step: "6", label: "用一用", text: "你统计了家里的书、天气和生日" },
] as const;

const REVIEW_DURATION = 3000; // 每条 3 秒自动切换

// ===== 第二层：选择补充选项 =====
const CHOICE_OPTIONS = [
  { key: "A", text: "收集数据前要先想好调查什么" },
  { key: "B", text: "不同的分类方式可能得到不同的结果" },
  { key: "C", text: "条形图能直观地比较数量多少" },
] as const;

// ===== 画图画布规格：8 列 × 4 行 =====
const CANVAS_COLS = 8;
const CANVAS_ROWS = 4;

// ===== 第三层：数据流程 =====
const FLOW = [
  { icon: "📋", name: "收集", desc: "用举手、投票等方法收集数据" },
  { icon: "📊", name: "整理", desc: "用正字法或表格记录整理" },
  { icon: "🔍", name: "分析", desc: "比较数据，发现规律" },
  { icon: "💡", name: "结论", desc: "得出结论，回答问题" },
] as const;

// ===== 第四层：发现卡要点 =====
const CARD_POINTS = [
  { icon: "✋", text: "数据收集可以用举手、投票等方法" },
  { icon: "📝", text: "整理数据可以用正字法或表格记录" },
  { icon: "📊", text: "条形图能直观地比较数量多少" },
] as const;

type Layer = "review" | "express" | "verify" | "card";
type ExpressTab = "fill" | "draw" | "choose";

export default function DiscoverPage() {
  const [layer, setLayer] = useState<Layer>("review");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // 完成卡片出现时标记 discover 步骤完成
  useEffect(() => {
    if (layer === "card") {
      markStepDone("data", "discover");
    }
  }, [layer]);

  // ===== 第一层：回顾 =====
  const [reviewIdx, setReviewIdx] = useState(0);
  const reviewDone = reviewIdx >= REVIEW_ITEMS.length;

  useEffect(() => {
    if (layer !== "review") return;
    if (reviewIdx >= REVIEW_ITEMS.length) return;
    const id = setTimeout(() => setReviewIdx((p) => p + 1), REVIEW_DURATION);
    return () => clearTimeout(id);
  }, [layer, reviewIdx]);

  // ===== 第二层：表达发现 =====
  const [tab, setTab] = useState<ExpressTab>("fill");
  const [fillA, setFillA] = useState("");
  const [fillB, setFillB] = useState("");
  const [fillC, setFillC] = useState("");
  // 画图：每列从底部向上填充的高度（0 ~ CANVAS_ROWS）
  const [colHeights, setColHeights] = useState<number[]>(
    Array.from({ length: CANVAS_COLS }, () => 0)
  );
  const [choice, setChoice] = useState<string | null>(null);
  const [customText, setCustomText] = useState("");

  const drawCount = colHeights.reduce((a, b) => a + b, 0);

  const tabValid =
    tab === "fill"
      ? fillA.trim() !== "" && fillB.trim() !== "" && fillC.trim() !== ""
      : tab === "draw"
        ? drawCount > 0
        : choice !== null && (choice !== "D" || customText.trim() !== "");

  const buildExpression = (): string => {
    if (tab === "fill")
      return `我发现：数据收集用 ${fillA.trim()}，整理用 ${fillB.trim()}，条形图能看出 ${fillC.trim()}`;
    if (tab === "draw")
      return `我画了一个条形图，共填了 ${drawCount} 个格子`;
    if (choice === "D") return `我的发现：${customText.trim()}`;
    const opt = CHOICE_OPTIONS.find((o) => o.key === choice);
    return opt ? `我选 ${choice}：${opt.text}` : "";
  };

  const toggleCell = (r: number, c: number) => {
    setColHeights((prev) => {
      const next = [...prev];
      const level = CANVAS_ROWS - r; // 点击该格对应的列高
      next[c] = next[c] === level ? 0 : level;
      return next;
    });
  };

  // ===== 第三层：验证 =====
  const [expression, setExpression] = useState("");
  const [flowStep, setFlowStep] = useState(0); // 0..FLOW.length，到 4 表示全部点亮

  useEffect(() => {
    if (layer !== "verify") return;
    if (flowStep >= FLOW.length) return;
    const id = setTimeout(() => setFlowStep((p) => p + 1), 900);
    return () => clearTimeout(id);
  }, [layer, flowStep]);

  const goVerify = () => {
    setExpression(buildExpression());
    setFlowStep(0);
    setLayer("verify");
  };

  const replay = () => {
    setLayer("review");
    setReviewIdx(0);
    setTab("fill");
    setFillA("");
    setFillB("");
    setFillC("");
    setColHeights(Array.from({ length: CANVAS_COLS }, () => 0));
    setChoice(null);
    setCustomText("");
    setExpression("");
    setFlowStep(0);
  };

  return (
    <StepShell topicId={topicId} stepId="discover">
      <div className="space-y-6">
        {/* ===== 第一层：回顾 ===== */}
        {layer === "review" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                我们一起走过的路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                回顾这 6 步，你做了好多事！
              </p>

              <div
                className="mt-6 flex min-h-[150px] cursor-pointer items-center justify-center"
                onClick={() => reviewIdx < REVIEW_ITEMS.length && setReviewIdx((p) => p + 1)}
              >
                {reviewIdx < REVIEW_ITEMS.length ? (
                  <div key={reviewIdx} className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-5xl animate-bounce-soft">{REVIEW_ITEMS[reviewIdx].icon}</div>
                    <p className="mt-3 text-lg font-medium text-[var(--text)]">
                      {REVIEW_ITEMS[reviewIdx].step}. {REVIEW_ITEMS[reviewIdx].label}
                    </p>
                    <p className="mt-1 text-[var(--text-secondary)]">{REVIEW_ITEMS[reviewIdx].text}</p>
                  </div>
                ) : (
                  <div className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-4xl">🌟</div>
                    <p className="mt-2 text-lg font-semibold text-[var(--text)]">6 步走完啦！</p>
                  </div>
                )}
              </div>

              {/* 进度点 */}
              <div className="mt-4 flex justify-center gap-2">
                {REVIEW_ITEMS.map((it, i) => (
                  <div
                    key={it.step}
                    className={`h-2 w-2 rounded-full transition-colors ${
                      i < reviewIdx
                        ? "bg-[var(--signal-confirmed)]"
                        : i === reviewIdx
                          ? "bg-[var(--signal-focus)]"
                          : "bg-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>
              <p className="mt-2 text-center text-xs text-[var(--text-muted)]">点击卡片可以快进</p>
            </section>

            {reviewDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm font-medium text-[var(--text)]">
                  数据会说话，你想说什么？
                </p>
                <div className="mt-4 text-center">
                  <button
                    onClick={() => setLayer("express")}
                    className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    说说我的发现 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第二层：表达发现（三选一） ===== */}
        {layer === "express" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">你发现了什么？</h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                选一种你喜欢的方式表达出来（三选一）
              </p>
            </section>

            {/* 选项卡 */}
            <div className="flex justify-center gap-2">
              {(
                [
                  { key: "fill", icon: "🖊️", label: "填一填" },
                  { key: "draw", icon: "🎨", label: "画条形图" },
                  { key: "choose", icon: "💬", label: "选一选" },
                ] as { key: ExpressTab; icon: string; label: string }[]
              ).map((t) => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                    tab === t.key
                      ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
                  }`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {/* 填一填 */}
            {tab === "fill" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="space-y-5 text-[var(--text)]">
                  <p className="flex flex-wrap items-center gap-2">
                    数据收集的方法有
                    <input
                      type="text"
                      value={fillA}
                      onChange={(e) => setFillA(e.target.value)}
                      placeholder="举手 / 投票"
                      className="w-32 rounded-lg border-2 border-[var(--border)] px-3 py-1.5 text-center font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    />
                  </p>
                  <p className="flex flex-wrap items-center gap-2">
                    整理数据可以用
                    <input
                      type="text"
                      value={fillB}
                      onChange={(e) => setFillB(e.target.value)}
                      placeholder="正字法 / 表格"
                      className="w-36 rounded-lg border-2 border-[var(--border)] px-3 py-1.5 text-center font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    />
                  </p>
                  <p className="flex flex-wrap items-center gap-2">
                    条形图能让我们一眼看出
                    <input
                      type="text"
                      value={fillC}
                      onChange={(e) => setFillC(e.target.value)}
                      placeholder="多少"
                      className="w-28 rounded-lg border-2 border-[var(--border)] px-3 py-1.5 text-center font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    />
                  </p>
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  把你学到的数据方法填进空里
                </p>
              </section>
            )}

            {/* 画条形图 */}
            {tab === "draw" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  点击格子，自由画一个简单的条形图
                </p>
                <div
                  className="mx-auto mt-4 grid w-full max-w-[420px] gap-1.5"
                  style={{ gridTemplateColumns: `repeat(${CANVAS_COLS}, 1fr)` }}
                >
                  {Array.from({ length: CANVAS_COLS * CANVAS_ROWS }, (_, idx) => {
                    const r = Math.floor(idx / CANVAS_COLS);
                    const c = idx % CANVAS_COLS;
                    const filled = r >= CANVAS_ROWS - colHeights[c];
                    return (
                      <button
                        key={idx}
                        type="button"
                        aria-label={`第 ${c + 1} 列第 ${r + 1} 行`}
                        onClick={() => toggleCell(r, c)}
                        className={`aspect-square rounded-md transition-all duration-150 ${
                          filled
                            ? "bg-[var(--signal-confirmed)]"
                            : "border-2 border-dashed border-[var(--signal-pending)] hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/20"
                        }`}
                      />
                    );
                  })}
                </div>
                <div className="mt-3 flex items-center justify-center gap-3 text-sm text-[var(--text-secondary)]">
                  <span>
                    共填 <span className="font-bold text-[var(--text)]">{drawCount}</span> 格
                  </span>
                  {drawCount > 0 && (
                    <button
                      onClick={() => setColHeights(Array.from({ length: CANVAS_COLS }, () => 0))}
                      className="text-xs text-[var(--text-muted)] underline"
                    >
                      清空
                    </button>
                  )}
                </div>
              </section>
            )}

            {/* 选一选 */}
            {tab === "choose" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="space-y-3">
                  {CHOICE_OPTIONS.map((opt) => (
                    <button
                      key={opt.key}
                      onClick={() => setChoice(opt.key)}
                      className={`flex w-full items-center gap-3 rounded-lg border-2 px-4 py-3 text-left transition-all ${
                        choice === opt.key
                          ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                          : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--signal-focus)]/50"
                      }`}
                    >
                      <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                        {opt.key}
                      </span>
                      <span className="text-[var(--text)]">{opt.text}</span>
                    </button>
                  ))}

                  {/* D 自定义 */}
                  <div
                    className={`flex items-center gap-3 rounded-lg border-2 px-4 py-3 transition-all ${
                      choice === "D"
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    <button
                      onClick={() => setChoice("D")}
                      className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]"
                      aria-label="选项 D"
                    >
                      D
                    </button>
                    <input
                      type="text"
                      value={customText}
                      onChange={(e) => {
                        setCustomText(e.target.value);
                        setChoice("D");
                      }}
                      placeholder="写下你自己的发现…"
                      className="flex-1 bg-transparent text-[var(--text)] placeholder:text-[var(--text-muted)] focus:outline-none"
                    />
                  </div>
                </div>
              </section>
            )}

            {/* 下一步 */}
            <div className="flex justify-center">
              <button
                onClick={goVerify}
                disabled={!tabValid}
                className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
              >
                看看数据流程 →
              </button>
            </div>
          </div>
        )}

        {/* ===== 第三层：验证（数据流程图） ===== */}
        {layer === "verify" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                数据走过的四步路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                收集 → 整理 → 分析 → 结论，一步一步亮起来
              </p>

              <div className="mt-6 flex flex-wrap items-center justify-center gap-2">
                {FLOW.map((f, i) => (
                  <Fragment key={f.name}>
                    <div
                      className={`flex w-28 flex-col items-center rounded-[var(--radius-sm)] border-2 p-3 transition-all duration-300 ${
                        i < flowStep
                          ? "border-[var(--signal-confirmed)] bg-[var(--signal-confirmed)]/10 shadow-[var(--shadow-sm)]"
                          : "border-[var(--border)] bg-[var(--bg-soft)] opacity-60"
                      }`}
                    >
                      <div className={`text-3xl ${i < flowStep ? "animate-bounce-soft" : ""}`}>
                        {f.icon}
                      </div>
                      <div className="mt-1 font-bold text-[var(--text)]">{f.name}</div>
                      <div className="mt-0.5 text-center text-[10px] leading-tight text-[var(--text-secondary)]">
                        {f.desc}
                      </div>
                    </div>
                    {i < FLOW.length - 1 && (
                      <div
                        className={`text-2xl font-bold transition-colors duration-300 ${
                          i < flowStep - 1
                            ? "text-[var(--signal-confirmed)]"
                            : "text-[var(--signal-pending)]"
                        }`}
                      >
                        →
                      </div>
                    )}
                  </Fragment>
                ))}
              </div>

              <div className="mt-4 text-center text-sm text-[var(--text-secondary)]">
                已点亮 <span className="font-bold text-[var(--text)]">{Math.min(flowStep, FLOW.length)}</span> /{" "}
                {FLOW.length} 步
              </div>
            </section>

            {flowStep >= FLOW.length && (
              <div className="flex justify-center">
                <button
                  onClick={() => setLayer("card")}
                  className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  查看发现卡 →
                </button>
              </div>
            )}
          </div>
        )}

        {/* ===== 第四层：我的数据发现卡 ===== */}
        {layer === "card" && (
          <div className="space-y-6">
            {/* 渐变边框：嵌套 div + absolute 渐变背景层 */}
            <section className="relative rounded-[var(--radius)] p-[3px] shadow-[var(--shadow-lg)]">
              <div
                className="absolute inset-0 rounded-[var(--radius)]"
                style={{
                  background:
                    "linear-gradient(135deg, var(--accent), var(--primary), var(--accent2), var(--accent3))",
                }}
              />
              <div className="relative rounded-[var(--radius)] bg-[var(--bg-card)] p-6">
                {/* 卡头 */}
                <div className="flex items-center justify-between border-b border-dashed border-[var(--border)] pb-4">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">🌟</span>
                    <div>
                      <h3 className="text-lg font-bold text-[var(--text)]">我的数据发现卡</h3>
                      <p className="text-xs text-[var(--text-muted)]">
                        数据的收集与整理 · 七步探索
                      </p>
                    </div>
                  </div>
                  <span className="rounded-full bg-[var(--signal-focus)] px-3 py-1 text-xs font-bold text-[var(--text)]">
                    完成
                  </span>
                </div>

                {/* 我的表达 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">我的发现</p>
                  <p className="mt-1 rounded-lg bg-[var(--bg-soft)] px-4 py-3 text-[var(--text)]">
                    {expression}
                  </p>
                </div>

                {/* 三个要点 */}
                <div className="mt-4 space-y-2.5">
                  {CARD_POINTS.map((p) => (
                    <div
                      key={p.text}
                      className="flex items-center gap-3 rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3"
                    >
                      <span className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-lg">
                        {p.icon}
                      </span>
                      <span className="text-[var(--text)]">{p.text}</span>
                    </div>
                  ))}
                </div>

                {/* 回顾六步 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">我走过的 6 步</p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {REVIEW_ITEMS.map((it) => (
                      <span
                        key={it.step}
                        className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-2.5 py-1 text-xs text-[var(--text-secondary)]"
                      >
                        <span>{it.icon}</span>
                        {it.label}
                      </span>
                    ))}
                  </div>
                </div>

                {/* 卡尾 */}
                <div className="mt-5 rounded-lg bg-[var(--signal-focus)]/15 px-4 py-4 text-center">
                  <p className="text-sm font-bold text-[var(--text)]">
                    🎉 你已经完成了数据的收集与整理的全部学习！
                  </p>
                </div>

                <div className="mt-4 flex items-center justify-between border-t border-dashed border-[var(--border)] pt-4">
                  <span className="text-xs text-[var(--text-muted)]">{completeMsg}</span>
                  <span className="text-xs text-[var(--text-muted)]">🌟 数据会说话</span>
                </div>
              </div>
            </section>

            <p className="text-center text-xs text-[var(--text-muted)]">
              💡 提示：可以截图保存这张卡片哦
            </p>

            <div className="flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={replay}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              <Link
                href={`/learn/${topicId}`}
                className="rounded-full bg-[var(--signal-confirmed)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                回到数据主页
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
